#!/usr/bin/env node
/**
 * M3 — port the legacy Mintlify pages into `docs-site/docs/`.
 *
 * Reads from `docs/` (which stays UNTOUCHED and authoritative until the C6 cutover) and writes a
 * transformed copy. Re-runnable: it overwrites its own output, never edits the source.
 *
 * Scope is the 128 pages with real content, per the approved page map + the sidebar generator's
 * accounting (34 Handbook withheld, 54 body-less `openapi:` stubs regenerated by the plugin in M4).
 *
 * Transforms, each driven by a MEASURED case in the real content — not speculation:
 *  1. Frontmatter: Mintlify `title`/`description`/`sidebarTitle` are kept (Docusaurus understands
 *     them); `icon:` is dropped (Mintlify's Font Awesome name — meaningless here, and M5 owns icons).
 *  2. `<Snippet file="x.mdx" />` -> MDX import of the corresponding partial. 21 call sites; Mintlify
 *     resolves a build-time path, which MDX cannot do from a runtime prop.
 *  3. MDX v3 strictness (the migration's main risk). Measured hazards across the 128 pages:
 *       - `{...}` in prose (8 pages) — MDX evaluates braces as a JS expression.
 *       - bare `<` in prose (2 pages, e.g. "< 0.45.0") — MDX starts parsing a JSX tag.
 *     Both are escaped ONLY outside fenced/inline code, where they are legitimate.
 *  4. `/resources/...` asset paths -> `/img/...` (Docusaurus serves `static/` at the site root).
 */
const fs = require('fs')
const path = require('path')

const DOCS = path.join(__dirname, '..')
const OUT = path.join(DOCS, '..', 'docs-site', 'docs')

const rows = JSON.parse(fs.readFileSync(path.join(__dirname, '_nav-inventory.json'), 'utf8'))
const toPort = rows.filter(
    (r) => r.tab !== 'Handbook' && !(r.tab === 'API Reference' && r.group !== 'Get Started'),
)

const SNIPPET_TO_PARTIAL = {
    'enterprise-feature.mdx': {name: 'EnterpriseFeature', file: '_enterprise-feature.mdx'},
    'execution-mode.mdx': {name: 'ExecutionMode', file: '_execution-mode.mdx'},
    'replace-oauth2-apps.mdx': {name: 'ReplaceOauth2Apps', file: '_replace-oauth2-apps.mdx'},
}

/**
 * Apply `fn` only to prose — never inside fenced blocks or inline code, where `<` and `{` are
 * legitimate and must survive verbatim.
 */
function inProseOnly(source, fn) {
    // Split on fenced blocks first, then inline code, keeping the delimiters as untouched segments.
    return source
        .split(/(```[\s\S]*?```)/g)
        .map((chunk) =>
            chunk.startsWith('```')
                ? chunk
                : chunk.split(/(`[^`\n]*`)/g).map((bit) => (bit.startsWith('`') ? bit : fn(bit))).join(''),
        )
        .join('')
}

function transform(source, docId) {
    const notes = []
    let out = source

    // --- 1. Frontmatter -------------------------------------------------------------------
    out = out.replace(/^---\r?\n([\s\S]*?)\r?\n---/, (_m, fm) => {
        const kept = fm
            .split(/\r?\n/)
            // `icon:` is a Mintlify Font Awesome name; we do not ship FA and M5 owns the icon system.
            .filter((line) => !/^icon:\s/.test(line))
        return `---\n${kept.join('\n')}\n---`
    })

    // --- 2. Snippets -> partial imports ---------------------------------------------------
    const imports = []
    out = out.replace(/<Snippet\s+file="([^"]+)"\s*\/>/g, (m, file) => {
        const partial = SNIPPET_TO_PARTIAL[file]
        if (!partial) {
            notes.push(`UNMAPPED SNIPPET: ${file}`)
            return m
        }
        const rel = path.relative(path.dirname(docId), '_partials/' + partial.file).replace(/\\/g, '/')
        const spec = rel.startsWith('.') ? rel : './' + rel
        const stmt = `import ${partial.name} from '${spec}';`
        if (!imports.includes(stmt)) imports.push(stmt)
        return `<${partial.name} />`
    })
    if (imports.length > 0) {
        // Imports sit after the frontmatter, and MUST be followed by a blank line — otherwise MDX
        // reads an immediately-adjacent `<Component />` as part of the import statement and acorn
        // fails with "Could not parse import/exports".
        out = out.replace(/^(---\r?\n[\s\S]*?\r?\n---\r?\n)/, `$1\n${imports.join('\n')}\n\n`)
    }

    // --- 3. MDX v3 strictness -------------------------------------------------------------
    // Escape ONLY real prose. Braces are meaningful in JSX attributes (`<CardGroup cols={2}>`), so
    // escaping them there breaks the tag — split the text on JSX tags and leave the tags alone.
    out = inProseOnly(out, (chunk) =>
        chunk
            .split(/(<\/?[A-Za-z][^>]*>)/g)
            .map((seg) => {
                if (seg.startsWith('<')) return seg // a JSX tag — never touch its attributes
                return (
                    seg
                        // Normalise Mintlify-era escapes (`{original name\}`, `\{ a \}`) back to bare
                        // braces FIRST — both delimiters, or the re-escape below doubles them up.
                        .replace(/\\([{}])/g, '$1')
                        // Braces MDX would evaluate as an expression (measured: `{connection: undefined}`).
                        .replace(/\{([^}\n]*)\}/g, (_m, inner) => `\\{${inner}\\}`)
                        // A `<` not starting a tag/comment/close — measured: "< 0.45.0".
                        .replace(/<(?![A-Za-z/!])/g, '&lt;')
                )
            })
            .join(''),
    )

    // --- 3b. Rebrand: canonical URLs + emails (owner-approved; see _decisions-log.md §3) ----
    // Order matters — the most specific path must win before the bare-host rule.
    // NOTE only the GitHub URL is verified to exist; the rest are the agreed naming convention and
    // still need the hosts stood up (or the reference dropped) before launch.
    const URL_MAP = [
        [/https:\/\/cloud\.activepieces\.com\/api/g, 'https://api.intellisper.com'],
        [/https:\/\/cloud\.activepieces\.com/g, 'https://cloud.intellisper.com'],
        [/https:\/\/github\.com\/activepieces\/activepieces/g, 'https://github.com/Kurvant/Intellisper'],
        [/https:\/\/cdn\.activepieces\.com\/pieces\//g, 'https://cdn.intellisper.com/blocks/'],
        [/https:\/\/cdn\.activepieces\.com/g, 'https://cdn.intellisper.com'],
        [/https:\/\/community\.activepieces\.com/g, 'https://community.intellisper.com'],
        [/https:\/\/demo\.activepieces\.com/g, 'https://demo.intellisper.com'],
        [/https:\/\/www\.activepieces\.com\/pieces\/ai/g, 'https://intellisper.com/blocks/ai'],
        [/https:\/\/www\.activepieces\.com\/pieces/g, 'https://intellisper.com/blocks'],
        [/https:\/\/www\.activepieces\.com/g, 'https://intellisper.com'],
        [/([a-zA-Z.]+)@activepieces\.com/g, '$1@intellisper.com'],
        // Bare hosts used as LINK TEXT, e.g. `[cloud.activepieces.com](…)` — the href rules above
        // only match `https://…`, so the visible label would keep the old brand.
        [/\bcloud\.activepieces\.com/g, 'cloud.intellisper.com'],
        [/\bwww\.activepieces\.com/g, 'intellisper.com'],
    ]
    for (const [pattern, replacement] of URL_MAP) out = out.replace(pattern, replacement)

    // The Handbook is withheld from the public site, so this public page cannot link into it. The
    // marketing site already carries the changelog. (Owner decision — _decisions-log.md §2b.)
    out = out.replace(
        /\(\/handbook\/engineering\/onboarding\/release-cycle\)/g,
        '(https://intellisper.com/release)',
    )

    // --- 3c. Code-sample identifiers (verified against source — _decisions-log.md §3c) ----------
    // `piecesFilterType` is a REAL BUG, not cosmetics: the embed JWT field is `blocksFilterType`
    // (packages/shared/.../project.ts:42, project-requests.ts:15, billing/index.ts:15). A customer
    // copying the documented payload sends a field the server ignores, so block filtering silently
    // never applies.
    out = out.replace(/\bpiecesFilterType\b/g, 'blocksFilterType')
    // The customer's OWN env var name in a JWT-signing sample — nothing in this repo reads it, so
    // renaming is safe and keeps the sample on-brand.
    out = out.replace(/\bACTIVEPIECES_SIGNING_KEY\b/g, 'INTELLISPER_SIGNING_KEY')
    // NOT renamed: `activePiecesUrl` — a Pulumi OUTPUT from a deploy template that is not in this
    // repo. The docs describe what that template actually prints; renaming the prose would make it
    // wrong. Fix the template first, then the docs. (_decisions-log.md §3c.)

    // --- 3d. MCP stepType enums (verified per-tool — _decisions-log.md §5) ---------------------
    // The docs document values the MCP tools REJECT. Two different tools use two different enums,
    // so a blanket PIECE->BLOCK replace would be wrong:
    //   ib_validate_step_config -> 'BLOCK_ACTION' | 'BLOCK_TRIGGER' | CODE | LOOP_ON_ITEMS | ROUTER
    //                              (ib-validate-step-config.ts:51)
    //   ib_add_step / ib_build_flow -> FlowActionType.BLOCK  (ib-add-step.ts:26, ib-build-flow.ts:22)
    // Longest-first so PIECE_ACTION is not clipped to BLOCK_ACTION by the bare-PIECE rule.
    if (docId === 'mcp/tools') {
        out = out
            .replace(/\bPIECE_ACTION\b/g, 'BLOCK_ACTION')
            .replace(/\bPIECE_TRIGGER\b/g, 'BLOCK_TRIGGER')
            .replace(/\bPIECE\b/g, 'BLOCK')
            .replace(/\bPIECE types\b/g, 'BLOCK types')
    }

    // --- 3e. Broken in-page anchors (slug drift Mintlify -> Docusaurus; _decisions-log.md §4) ----
    // Docusaurus uses github-slugger; Mintlify slugified differently, so links that worked before
    // now miss. Verified per anchor against the real slugger output — not guessed.
    //
    // (a) Changelog date headings: Mintlify encoded `03/07/2025 (0.5.0)` as `03%2F07%2F2025-0-5-0`;
    //     Docusaurus strips the slashes -> `03072025-050`.
    out = out.replace(
        /#(\d{2})%2F(\d{2})%2F(\d{4})-(\d)-(\d)-(\d)/g,
        (_m, d1, d2, y, a, b, c) => `#${d1}${d2}${y}-${a}${b}${c}`,
    )
    // (b) `Files & flow run logs`: the `&` becomes an extra dash -> `files--flow-run-logs`.
    out = out.replace(/#files-flow-run-logs\b/g, '#files--flow-run-logs')
    // (c) `#configure-parameters` and `#setting-block-source` point at BOLD lines, not headings, so
    //     no slug is ever generated. Promote those two lines to real `####` headings (they read as
    //     section labels already), which both creates the anchor and matches the existing links.
    if (docId === 'embedding/embed-builder') {
        out = out.replace(/^\*\*Configure Parameters:\*\*/m, '#### Configure Parameters')
    }
    if (docId === 'install/configuration/environment-variables') {
        // `[Setting Block Source](#setting-block-source)` has NO target on this page — the section it
        // points to lives only in the withheld Handbook (`run-ee.mdx`). So the link is genuinely
        // dead, not a slug mismatch. Strip the dead link, keep the label as plain text. The real
        // content (a public "Setting Block Source" section) is C-phase authoring work — flagged in
        // _decisions-log.md §4.
        out = out.replace(/\[Setting Block Source\]\(#setting-block-source\)/g, 'Setting Block Source')
    }
    // (d) `[check docs](/endpoints/embedding/add-allowed-embed-origins)` on the breaking-changes page
    //     points at a dedicated "add allowed embed origins" endpoint. VERIFIED against code: this fork
    //     has NO such route — `AddAllowedEmbedOriginsRequestBody` is a registered schema (app.ts:459)
    //     used by no handler; allowed origins are set as the `allowedEmbedOrigins` field on the platform
    //     (platform.request.ts, applied via the platform update route). So the link is a phantom, not a
    //     slug miss. Rewrite the claim to match reality (a platform setting, not a new endpoint) and
    //     delink. See _decisions-log.md §4 and _openapi-schema-worklist.md (embedding phantom).
    if (docId === 'install/configuration/breaking-changes') {
        out = out.replace(
            /a new endpoint for adding these origins — \[check docs\]\(\/endpoints\/embedding\/add-allowed-embed-origins\)\./g,
            'the allowed origins are configured per platform via the `allowedEmbedOrigins` platform setting.',
        )
    }
    // (e) `debugging-runs`: the legacy step said "Go to the Dashboard, click on Runs". VERIFIED against
    //     the current UI nav (`packages/web/src/app/components/overhaul/domain-nav.ts:85-86`): Runs now
    //     lives under the **Operate** domain at `/operate/runs`. Correct the nav instruction.
    if (docId === 'flows/debugging-runs') {
        out = out.replace(
            /Go to the Dashboard, click on \*\*Runs\*\*\./g,
            'Go to **Operate → Runs**.',
        )
    }

    // --- 3f. Remaining activepieces strings — LOW-consequence rebrands (ACTIVEPIECES_STRING_AUDIT.md)
    // Applied here because they carry no risk: docs text with no code reference, or values this repo
    // demonstrably owns. The HIGH-consequence ones (Conjur policy IDs, fork upstream, Pulumi output,
    // third-party listing URLs) are DELIBERATELY LEFT and flagged in the audit — see §"consequential".
    //
    // Docker IMAGE only. `activepieces/activepieces` is context-dependent — it is ALSO a git remote
    // (`git@github.com:activepieces/activepieces.git`), a Conjur policy id
    // (`conjur:host:activepieces/activepieces`), and a Docker Hub listing URL
    // (`hub.docker.com/r/activepieces/activepieces`). Those must NOT change (see the audit's
    // "consequential" section). So match ONLY where it is an image reference — either tagged
    // (`activepieces/activepieces:latest`) or the bare `image: activepieces/activepieces` YAML key —
    // and NEVER when preceded by `:` , `/` or `github.com`.
    // Guard: only ever rewrite an image ref when it is NOT part of a URL/host path. A `/` or `.`
    // immediately before `activepieces/…` means it is a github/dockerhub URL — leave it.
    const imageRepl = (m, pre) => (/[/.]$/.test(pre) ? m : `${pre}ghcr.io/kurvant/intellisper`)
    out = out
        // Tagged image, but not inside a URL host (no `/` or `.` immediately before).
        .replace(/([^/.])activepieces\/activepieces(:[\w.-]+)/g, (_m, pre, tag) => `${pre}ghcr.io/kurvant/intellisper${tag}`)
        // Untagged image in the known command/YAML positions: `image:`, a list item `- `, `docker
        // pull `, `--name <x> `, or an env-prefixed run (`…=… activepieces/activepieces`). Each of
        // these is preceded by whitespace or `:` and is NOT a URL.
        .replace(/(\bimage:\s+|-\s+|pull\s+|"\s+|_name\s+)activepieces\/activepieces\b(?!:)(?![/.\w-]*activepieces)/g, imageRepl)
        // `- Image: activepieces/activepieces` (capital-I prose label, e.g. the GCP guide).
        .replace(/(\bImage:\s+)activepieces\/activepieces\b(?!:)/g, '$1ghcr.io/kurvant/intellisper')
    // GHCR package path was half-rebranded (org became Kurvant/Intellisper, package still said
    // activepieces). Point at the intellisper container package.
    out = out.replace(/(github\.com\/Kurvant\/Intellisper\/pkgs\/container\/)activepieces/g, '$1intellisper')
    // SCIM placeholder host.
    out = out.replace(/your-activepieces-domain/g, 'your-intellisper-domain')
    // Branded screenshot filename (asset copied to the intellisper name in static/img).
    out = out.replace(/using-activepieces-debugging\.png/g, 'using-intellisper-debugging.png')
    // npm scope search for blocks (the published scope is @intelblocks).
    out = out.replace(/%40activepieces%2Fpiece-/g, '%40intelblocks%2Fblock-')
    // 'activepieces.com' as bare LINK TEXT (the href was already rebranded in step 3b).
    out = out.replace(/\[activepieces\.com\]/g, '[intellisper.com]')

    // --- 3g. C3 factual drift corrections (verified vs code; see docs/rewrite/_c3-drift.md) ----------
    // Each correction below was confirmed against server/shared code. Only SAFE, code-verified fixes are
    // applied here; borderline / owner-input items are left untouched and flagged in _c3-drift.md.

    // (i) EMBED JWT — the biggest defect. Verified payload shape (external-token-extractor.ts:27-36):
    //     { externalUserId, externalProjectId, firstName, lastName, role, blocks?:{filterType,tags},
    //       concurrencyPoolKey?, concurrencyPoolLimit? }. Docs shipped a FLAT `blocksFilterType`, phantom
    //     `piecesTags`/`version`/`tasks`/`aiCredits`/`projectDisplayName`, and UPPERCASE role values
    //     (code looks up the role by exact name Admin/Editor/Viewer → uppercase throws not-found).
    //     NB: §3c already turns piecesFilterType→blocksFilterType earlier; here we fix SHAPE + values.
    if (docId === 'embedding/provision-users') {
        // JSON example block: drop phantom claims, fix role case, nest the filter under `blocks`.
        out = out.replace(/^\s*"version": "v3",\n/m, '')
        out = out.replace(/"role": "EDITOR"/g, '"role": "Editor"')
        out = out.replace(/"(?:pieces|blocks)FilterType": "NONE",/g, '"blocks": { "filterType": "NONE", "tags": [] },')
        out = out.replace(/^\s*"tasks": 50000,\n/m, '')
        out = out.replace(/^\s*"aiCredits": 250\n/m, '')
        // Node example block (unquoted keys): same fixes.
        out = out.replace(/^\s*version: "v3",\n/m, '')
        out = out.replace(/role: "EDITOR",/g, 'role: "Editor",')
        out = out.replace(/(?:pieces|blocks)FilterType: "NONE",/g, 'blocks: { filterType: "NONE", tags: [] },')
        // Claims table: remove phantom rows, correct role example values.
        out = out.replace(/^\s*\| projectDisplayName\|.*\|\n/m, '')
        out = out.replace(/\(e\.g\., \*\*EDITOR\*\*, \*\*VIEWER\*\*, \*\*ADMIN\*\*\)/g, '(e.g., **Admin**, **Editor**, **Viewer**)')
        out = out.replace(/^\s*\| (?:pieces|blocks)FilterType\s*\|.*\|\n/m, '    | blocks.filterType | Block filtering for the project (`NONE` or `ALLOWED`), check [customize blocks](/embedding/customize-blocks) |\n')
        out = out.replace(/^\s*\| piecesTags\s*\|.*\|\n/m, '    | blocks.tags       | Block tags to sync to the project, check [customize blocks](/embedding/customize-blocks) |\n')
        out = out.replace(/^\s*\| tasks\s*\|.*\|\n/m, '')
        out = out.replace(/^\s*\| aiCredits\s*\|.*\|\n/m, '')
    }
    if (docId === 'embedding/customize-blocks') {
        // Correct the flat example to the real nested `blocks` claim.
        out = out.replace(
            /"(?:pieces|blocks)FilterType": "ALLOWED",\s*\n\s*"piecesTags": \[ "free" \]/,
            '"blocks": {\n            "filterType": "ALLOWED",\n            "tags": [ "free" ]\n        }',
        )
    }
    if (docId === 'embedding/sdk-changelog') {
        out = out.replace(/Acitvepieces/g, 'Intellisper')
    }

    // (ii) BUILD BLOCKS — `createPiece` snippets don't compile (framework exports only `createBlock`,
    //      piece.ts:76). Fix the import + any prose. Safe: `createBlock` is a drop-in with the same call.
    if (/^build-blocks\//.test(docId) || docId === 'build-blocks/block-reference/authentication') {
        out = out.replace(/\bcreatePiece\b/g, 'createBlock')
    }
    // Dev login email — the seeded dev user is dev@intellisper.local (dev-seeds.ts:35), not dev@ap.com.
    out = out.replace(/dev@ap\.com/g, 'dev@intellisper.local')
    // Fork/upstream git remotes → the real repo Kurvant/Intellisper (NOT the generic image rebrand).
    out = out.replace(/github\.com[/:]([A-Za-z0-9_-]*\/)?activepieces\/activepieces\.git/g, (m) =>
        m.includes('YOUR_USERNAME') ? m.replace(/activepieces\/activepieces\.git/, 'Intellisper.git') : m.replace(/activepieces\/activepieces\.git/, 'Kurvant/Intellisper.git'))
    out = out.replace(/(YOUR_USERNAME\/)activepieces\.git/g, '$1Intellisper.git')
    // Build tool: the repo migrated Nx → Turbo (turbo.json, no nx.json). Only outside the migration page.
    if (docId === 'build-blocks/block-reference/external-libraries') {
        out = out.replace(/employing \*\*Nx\*\* as its build tool/g, 'employing **Turbo** as its build tool')
        out = out.replace(/employing Nx as its build tool/g, 'employing Turbo as its build tool')
    }
    // Residual placeholder wording (commands are correct; only the placeholder token leaks old brand).
    out = out.replace(/PIECE_FOLDER_NAME/g, 'BLOCK_FOLDER_NAME')
    out = out.replace(/<your_piece>/g, '<your_block>')
    // MCP subpath-deploy EXAMPLE url used /activepieces as the instance's own path prefix.
    if (docId === 'mcp/overview') {
        out = out.replace(/(https:\/\/your-instance\.com)\/activepieces/g, '$1/intellisper')
    }

    // (iii) DEPLOY / INSTALL env-var table — 6 wrong DEFAULTS + 4 phantom rows (verified vs system.ts /
    //       worker configs). Table cells: `| `IB_VAR` | desc | <default> | ... |`. Fix defaults by var.
    if (docId === 'install/configuration/environment-variables') {
        const fixDefault = (varName, wrong, right) => {
            // Replace the default cell on the row for this var: match `` `IB_VAR` `` … first `` `wrong` `` after it.
            const re = new RegExp('(`' + varName + '`[^\\n]*?)`' + wrong.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '`', 'm')
            out = out.replace(re, '$1`' + right + '`')
        }
        fixDefault('IB_CLOUD_AUTH_ENABLED', 'false', 'true')
        fixDefault('IB_QUEUE_UI_ENABLED', 'true', 'false')
        fixDefault('IB_REDIS_FAILED_JOB_RETENTION_MAX_COUNT', '2000', '100000')
        fixDefault('IB_POSTGRES_IDLE_TIMEOUT_MS', '30000', '300000')
        fixDefault('IB_PROJECT_RATE_LIMITER_ENABLED', 'true', 'false')
        fixDefault('IB_ISSUE_ARCHIVE_DAYS', '14', '7')
        // Remove phantom-variable rows entirely (these props/flags do not exist as env vars — verified).
        // IB_MAX_MCPS_PER_PROJECT is DELIBERATELY KEPT (it is a real ApFlagId — see _c3-drift.md).
        // Line-based removal (robust against per-row cell-count differences, e.g. the double-default rows).
        const phantoms = ['IB_BLOCKS_CACHE_MAX_ENTRIES', 'IB_BLOCKS_SOURCE', 'IB_TRIGGER_FAILURE_THRESHOLD', 'IB_MAX_TABLES_PER_PROJECT']
        out = out.split('\n').filter((line) => {
            const isTableRow = /^\s*\|/.test(line)
            return !(isTableRow && phantoms.some((p) => line.includes('`' + p + '`')))
        }).join('\n')
    }

    // (iv) DOCKER registry wording — the command pulls from ghcr.io, not Docker Hub.
    if (docId === 'install/options/docker') {
        out = out.replace(/from Docker Hub/g, 'from the GitHub Container Registry (ghcr.io)')
    }

    // (v) PERMISSIONS — the "Operator" role is INVENTED (verified: DefaultProjectRole = Admin/Editor/
    //     Viewer only, project-member.ts:1-5). Drop the "four roles" claim and the Operator column.
    if (docId === 'admin-guide/guides/permissions') {
        out = out.replace(/\bfour standard roles\b/g, 'three standard roles')
        // Remove the 4th (Operator) column from the permissions table. Operate only on the pipe-table
        // rows that carry the Operator header/cells; rebuild each by dropping cell index 3.
        const lines = out.split('\n')
        // Find the header row to locate the Operator column index within the table.
        const headerIdx = lines.findIndex((l) => /^\|\s*Permission\s*\|/.test(l) && /\bOperator\b/.test(l))
        if (headerIdx !== -1) {
            const opCol = lines[headerIdx].split('|').findIndex((c) => c.trim() === 'Operator')
            for (let i = headerIdx; i < lines.length; i++) {
                const line = lines[i]
                if (!/^\s*\|/.test(line)) break // end of the table
                const cells = line.split('|')
                if (opCol > 0 && opCol < cells.length) {
                    cells.splice(opCol, 1)
                    lines[i] = cells.join('|')
                }
            }
            out = lines.join('\n')
        }
    }

    // (vi) SCIM overview — add the Microsoft Entra ID card (the provider page ships but the overview
    //      only lists Okta). Insert an Entra card next to the Okta card in the Supported Providers group.
    if (docId === 'admin-guide/guides/scim/overview') {
        out = out.replace(
            /(<Card\s+title="Okta"[^>]*href="([^"]*okta[^"]*)"[^>]*>[\s\S]*?<\/Card>)/i,
            '$1\n  <Card title="Microsoft Entra ID" href="/admin-guide/guides/scim/providers/microsoft-entra-id">\n    Provision users and groups from Microsoft Entra ID via SCIM.\n  </Card>',
        )
    }

    // --- 4. Asset paths -------------------------------------------------------------------
    // Docusaurus serves `static/` at the site root, so every asset reference must be root-absolute.
    // The legacy content mixes root-absolute (`/resources/x.png`) and page-relative
    // (`../../resources/x.png`) forms; a naive `/resources/ -> /img/` swap leaves the relative ones
    // pointing at a path that does not exist (measured: 4 such images).
    out = out.replace(/(?:\.\.\/)+resources\//g, '/img/')
    out = out.replace(/\/resources\//g, '/img/')

    return {out, notes}
}

let ported = 0
const allNotes = []

// The 3 snippets become MDX partials. They must run through the SAME transform as every other page —
// they were hand-copied in M2 and so kept an `activepieces.com/sales` link that the rebrand missed.
// Porting them here means the script owns them and a re-run cannot leave them stale.
for (const [srcName, {file}] of Object.entries(SNIPPET_TO_PARTIAL)) {
    const src = path.join(DOCS, '_snippets', srcName)
    if (!fs.existsSync(src)) {
        allNotes.push(`MISSING SNIPPET SOURCE: ${srcName}`)
        continue
    }
    const {out, notes} = transform(fs.readFileSync(src, 'utf8'), '_partials/' + file)
    const dest = path.join(OUT, '_partials', file)
    fs.mkdirSync(path.dirname(dest), {recursive: true})
    fs.writeFileSync(dest, out)
    notes.forEach((n) => allNotes.push(`${srcName}: ${n}`))
}
for (const row of toPort) {
    const src = path.join(DOCS, row.page + '.mdx')
    if (!fs.existsSync(src)) {
        allNotes.push(`MISSING SOURCE: ${row.page}`)
        continue
    }
    const {out, notes} = transform(fs.readFileSync(src, 'utf8'), row.page)
    const dest = path.join(OUT, row.page + '.mdx')
    fs.mkdirSync(path.dirname(dest), {recursive: true})
    fs.writeFileSync(dest, out)
    ported++
    notes.forEach((n) => allNotes.push(`${row.page}: ${n}`))
}

console.log(`ported: ${ported} / ${toPort.length}`)
if (allNotes.length > 0) {
    console.log('\nNOTES (need a human look):')
    allNotes.forEach((n) => console.log('  ' + n))
} else {
    console.log('notes:  none')
}
